-- =============================================================================
-- SEED DATA: Random synthetic units for the 62 properties CCB_Template does
-- NOT define unit-level data for.
--
-- CCB_Template/lib/data/communities.ts declares a `totalUnits` figure on
-- every one of its 67 properties, but its `units` array only actually
-- generates unit rows for 5 of them (Rivera Towers A-E — see
-- seed-community-property-unit.sql, Step 3, 111 units). CCB_Template's own
-- CLAUDE.md separately states the REAL estate total is 1,828 units — the
-- per-property `totalUnits` fields only sum to ~1,322 (an acknowledged
-- "simplified mock data" figure, not the real one). This script targets the
-- real total.
--
-- Global targets (fixed data + this script's random data):
--   Total:    1828  (111 template + 1 pre-existing + 1716 here)
--   Occupied: 1367  (83 template + 0 pre-existing + 1284 here)
--   Vacant:    461  (28 template + 1 pre-existing + 432 here)
--
-- Per-property counts here are the original template totalUnits figures
-- scaled up proportionally (largest-remainder rounding) so the 62-property
-- sum hits exactly 1716 — relative tower sizes are preserved,
-- only the absolute scale changes. Occupied/vacant labels are drawn from a
-- single shuffled pool sized to hit the exact global 1284/432 split across
-- these 62 properties, so per-property occupancy still looks organic
-- rather than a fixed percentage per tower.
--
-- unit_number = "{property_code}-{seq}" (e.g. "AZP-T01-01"). owner_id /
-- tenant_id / master_meter_id / sub_meter_id use an "X" marker
-- (OWNX/TENX/MMTX/SMTX) to stay visually distinguishable from the
-- template-sourced OWN/TEN/MMT/SMT codes in seed-community-property-unit.sql.
--
-- Prerequisite: run seed-community-property-unit.sql first.
--
-- Idempotent: this script deletes any previously-inserted MMTX-marked rows
-- before inserting (unit_number has no unique constraint, so without this
-- explicit cleanup, re-running would otherwise create duplicates).
-- =============================================================================

START TRANSACTION;

DELETE FROM units WHERE master_meter_id LIKE 'MMTX%';










UPDATE units SET business_code = CONCAT('UNT-', LPAD(id, 6, '0')) WHERE business_code IS NULL;

COMMIT;

-- ---------------------------------------------------------------------------
-- Verify: global totals should read 1828 / 1367 occupied / 461 vacant.
-- ---------------------------------------------------------------------------

SELECT occupancy_status, COUNT(*) AS cnt FROM units GROUP BY occupancy_status;
SELECT COUNT(*) AS grand_total FROM units;
